int main(){
	//声明一个顺序表并初始化
	SeqList list;
	initList(&list);
	printf("初始化成功,目前长度占用%d\n",list.length);
	printf("目前占用内存%zu字节\n",sizeof(list.data));
	appendElem(&list,88);
	appendElem(&list,45);
	appendElem(&list,43);
	appendElem(&list,17);
