### 顺序表的删除

#### C版本

```c
//删除
//pos=position  即删除位置
int deleteElem(SeqList*L,int pos,ElemType*e){
	if(L->length==0){
		printf("空表\n");
		return 0;
	}
	if(pos<1||pos>L->length){
		printf("删除数据位置有误\n");
		return 0;
	}

	*e=L->data[pos-1];
	if(pos<L->length){
		for(int i=pos;i<L->length;i++){
			L->data[i-1]=L->data[i];
		}
	}
	L->length--;
	return 1;
}
int main(){
	//声明一个顺序表并初始化
	SeqList list;
	initList(&list);
	appendElem(&list,88);
	appendElem(&list,45);
	appendElem(&list,43);
	appendElem(&list,17);
	listElem(&list);

	ElemType delData;
	deleteElem(&list,2,&delData);
	printf("被删除的数据为:%d\n",delData);
	listElem(&list);

	return 0;
}
```

#### Lua版本

```lua
--删除元素
function SeqList:deleteElem(pos)
    if #self.data == 0 then
        print("空表")
        return nil
    end
    if pos < 1 or pos > #self.data then
        print("删除数据位置有误")
        return nil
    end

    -- table.remove 会移除指定位置元素,并自动前移后续元素
    -- 它直接返回被移除的值
    local e = table.remove(self.data, pos)
    return e
end

local function main()
    local list = SeqList:new()

    -- 添加元素
    list:appendElem(88)
    list:appendElem(100)

    -- 遍历顺序表
    print("顺序表元素如下:")
    list:listElem()

    -- 删除(第一种,查看被删除的是谁)
    local delData = list:deleteElem(2)
    print("删除第2个位置的数据后,被删除的数据为:" .. delData)
    list:listElem()

    --删除(第二种,不需要看)
    list:deleteElem(2)
    print("删除第2个位置的数据后,顺序表元素如下:")
    list:listElem()
end

main()
```

#### C#版本

```c#
//定义顺序表类
public class SeqList
{
     //删除
    public int deleteElem(int pos, out ElemType e)
    {
        e = 0; // out 参数必须赋值

        if (length == 0)
        {
            Console.WriteLine("空表");
            return 0;
        }
        if (pos < 1 || pos > length)
        {
            Console.WriteLine("删除数据位置有误");
            return 0;
        }

        // 取出要删除的元素
        e = data[pos - 1];

        //直接调用 List.RemoveAt,底层自动处理移位
        data.RemoveAt(pos - 1);

        return 1;
    }
}

class Program
{
    static void Main(string[] args)
    {

        SeqList list = new SeqList();// 创建顺序表实例

        list.appendElem(23);
        list.appendElem(45);
        list.appendElem(88);
        Console.WriteLine("顺序表的元素有:");
        list.listElem();// 遍历顺序表

        ElemType deletedElem;//模拟C版本的可以查看删除的是什么
        list.deleteElem(2, out deletedElem);
        list.listElem();// 遍历顺序表
        Console.WriteLine("被删除的元素是:" + deletedElem);
    }
}
```

### 顺序表的指定位置插入

#### C版本

```c
//指定位置插入
int insertElem(SeqList*L,int pos,ElemType e){
	if(L->length>=MAXSIZE){
		printf("表已经满了\n");
		return 0;
	}
	if(pos<1||pos>L->length){
		printf("插入位置错误\n");
		return 0;
	}
	if(pos<=L->length){
		for(int i=L->length-1;i>=pos-1;i--){
			L->data[i+1]=L->data[i];
		}
		L->data[pos-1]=e;
		L->length++;
	}
	return 1;
}
int main(){
	//声明一个顺序表并初始化
	SeqList list;
	initList(&list);
	printf("初始化成功,目前长度占用%d\n",list.length);
	printf("目前占用内存%zu字节\n",sizeof(list.data));
	appendElem(&list,88);
	appendElem(&list,45);
	appendElem(&list,43);
	appendElem(&list,17);
	listElem(&list);
	insertElem(&list,2,18);
	listElem(&list);

	return 0;
}
```

# OK,在我们学习数据结构之前我们来先了解一个概念-------时间复杂度和空间复杂度还有抽象数据类型

# 开发者请注意,请不要看本篇文章,因为这都是没什么用的东西,只适合那些考试党

## 时间复杂度

时间复杂度,也称渐进时间复杂度,T(n)=O(f(n))

<img src="复杂度/image-20251225233723152.png" alt="image-20251225233723152" style="zoom: 50%;" />

随着问题规模n的增大,算法执行时间和增长率和f(n)增长率成正比

说人话就是:

> 时间复杂度 = 干活要花多少“时间”

举个例子

劳埃德给阿尼亚买了很多花生零食并嘱咐阿尼亚一次只能吃一袋,但是阿尼亚会选择吃完后继续偷吃,可不可以吃完一袋花生取决于阿尼亚酱的咀嚼速度,假如阿尼亚每次吃一个花生的速度和吞一整袋花生的速度一样,则称之为时间复杂度低,但是如果阿尼亚嘴里每增加一个花生,导致咀嚼的速度下降,结果直到黄昏回家被发现了也没吃完,这就是时间复杂度高

**低复杂度 O(1)：**
"无论劳埃德买1袋还是10袋花生，阿尼亚狂风吸入，所以黄昏回家前一定不被发现"

**高复杂度 O(n²)：**
"阿尼亚嘴里每多塞一颗1颗，咀嚼速度就慢一半，结果吃到第10颗时，单颗就要嚼好几分钟, 完了 ,那个间谍老爹回家了,来不及藏花生包装袋了 !!!"

